import { useTheme } from "~/hooks/useTheme";

export function ThemeSelector() {
  const { theme, setTheme, availableThemes } = useTheme();

  return (
    <section className="rounded-2xl border border-border bg-card p-5">
      <div className="mb-4">
        <h2 className="text-sm font-medium text-foreground">Appearance</h2>
        <p className="mt-1 text-xs text-muted-foreground">
          Choose a color theme for T3 Code.
        </p>
      </div>

      <div className="space-y-2" role="radiogroup" aria-label="Color theme">
        {availableThemes.map((t) => {
          const selected = theme.id === t.id;
          return (
            <button
              key={t.id}
              type="button"
              role="radio"
              aria-checked={selected}
              className={`flex w-full items-center justify-between rounded-lg border px-3 py-2.5 text-left transition-colors ${
                selected
                  ? "border-primary/60 bg-primary/8 text-foreground"
                  : "border-border bg-background text-muted-foreground hover:bg-accent"
              }`}
              onClick={() => setTheme(t)}
            >
              {/* Color swatches preview */}
              <span className="flex items-center gap-3">
                <span className="flex items-center gap-1" aria-hidden="true">
                  <span
                    className="block h-5 w-5 rounded-full border border-black/10"
                    style={{ background: t.colors.background }}
                  />
                  <span
                    className="block h-5 w-5 rounded-full border border-black/10"
                    style={{ background: t.colors.sidebar }}
                  />
                  <span
                    className="block h-5 w-5 rounded-full border border-black/10"
                    style={{ background: t.colors.primary }}
                  />
                </span>
                <span className="flex flex-col">
                  <span className="text-sm font-medium leading-tight">{t.name}</span>
                  <span className="text-xs leading-tight opacity-70">
                    {t.dark ? "Dark" : "Light"}
                  </span>
                </span>
              </span>

              {selected ? (
                <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Active
                </span>
              ) : null}
            </button>
          );
        })}
      </div>

      <p className="mt-4 text-xs text-muted-foreground">
        Active theme:{" "}
        <span className="font-medium text-foreground">{theme.name}</span>
      </p>
    </section>
  );
}

