    sidebar: "#0d1220",
    editor: "#0b0f1a",
    terminal: "#0e1321",
    statusBar: "#111827",
    statusBarForeground: "#5b7099",
  },
};

const BUILT_IN_THEMES: ReadonlyArray<Theme> = [T3_DARK, T3_LIGHT, T3_MIDNIGHT];

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Look up a theme by id. Returns the default theme (`t3-dark`) when no match
 * is found, so callers always receive a valid theme object.
 */
export function getTheme(id: string): Theme {
  return BUILT_IN_THEMES.find((t) => t.id === id) ?? T3_DARK;
}

/** Returns all built-in themes in display order. */
export function listThemes(): ReadonlyArray<Theme> {
  return BUILT_IN_THEMES;
}

