import { useCallback, useEffect, useSyncExternalStore } from "react";
import { type Theme, getTheme, listThemes } from "@t3tools/shared/themes";

export type { Theme };

const STORAGE_KEY = "t3code:theme-id";
const LEGACY_STORAGE_KEY = "t3code:theme";

let listeners: Array<() => void> = [];
let lastThemeId: string | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function migrateStoredTheme(): string {
  // Check for new key first
  const stored = localStorage.getItem(STORAGE_KEY);
  if (stored && getTheme(stored).id === stored) return stored;

  // Migrate from old key
  const legacy = localStorage.getItem(LEGACY_STORAGE_KEY);
  if (legacy === "light") return "t3-light";
  return "t3-dark";
}

function getStoredThemeId(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw && getTheme(raw).id === raw) return raw;
  return migrateStoredTheme();
}

function applyTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle dark class for Tailwind @variant dark
  document.documentElement.classList.toggle("dark", theme.dark);
  document.documentElement.style.setProperty("color-scheme", theme.dark ? "dark" : "light");

  // Inject all color CSS custom properties as inline styles on :root
  const c = theme.colors;
  const props: Array<[string, string]> = [
    ["--background", c.background],
    ["--foreground", c.foreground],
    ["--card", c.card],
    ["--card-foreground", c.cardForeground],
    ["--popover", c.popover],
    ["--popover-foreground", c.popoverForeground],
    ["--primary", c.primary],
    ["--primary-foreground", c.primaryForeground],
    ["--secondary", c.secondary],
    ["--secondary-foreground", c.secondaryForeground],
    ["--muted", c.muted],
    ["--muted-foreground", c.mutedForeground],
    ["--accent", c.accent],
    ["--accent-foreground", c.accentForeground],
    ["--destructive", c.destructive],
    ["--destructive-foreground", c.destructiveForeground],
    ["--border", c.border],
    ["--input", c.input],
    ["--ring", c.ring],
    ["--theme-sidebar", c.sidebar],
    ["--theme-editor", c.editor],
    ["--theme-terminal", c.terminal],
    ["--theme-status-bar", c.statusBar],
    ["--theme-status-bar-foreground", c.statusBarForeground],
    ["--theme-font-family", theme.fontFamily],
    ["--theme-font-size", `${theme.fontSize}px`],
  ];

  for (const [prop, value] of props) {
    document.documentElement.style.setProperty(prop, value);
  }

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getTheme(getStoredThemeId()));

function getSnapshot(): string {
  const id = getStoredThemeId();
  if (lastThemeId === id) return lastThemeId;
  lastThemeId = id;
  return id;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY || e.key === LEGACY_STORAGE_KEY) {
      applyTheme(getTheme(getStoredThemeId()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);
  const theme = getTheme(themeId);

  /** Preserved for backwards-compatibility with DiffWorkerPoolProvider */
  const resolvedTheme: "light" | "dark" = theme.dark ? "dark" : "light";

  const availableThemes = listThemes();

  const setTheme = useCallback((next: Theme | string) => {
    const id = typeof next === "string" ? next : next.id;
    const resolved = getTheme(id);
    localStorage.setItem(STORAGE_KEY, resolved.id);
    applyTheme(resolved, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, availableThemes, resolvedTheme } as const;
}
